<?php
require_once __DIR__ . '/bootstrap.php'; require_auth();
if(method()!=='POST')json_response(['error'=>'Method not allowed'],405); $pdo=db();$d=input_json();$trip=$d['trip']??[];$events=$d['events']??[];$packing=$d['packing']??[];$budget=$d['budget']??[];$pdo->beginTransaction();
try{$s=$pdo->prepare('INSERT INTO trips (name,destination,start_date,end_date,notes) VALUES (?,?,?,?,?)');$s->execute([clean_string($trip['name']??null,255)?:'Importert tur',clean_string($trip['destination']??null,255),clean_string($trip['start']??$trip['start_date']??null,20),clean_string($trip['end']??$trip['end_date']??null,20),clean_string($trip['notes']??null,5000)]);$tripId=(int)$pdo->lastInsertId();$es=$pdo->prepare('INSERT INTO events (trip_id,event_type,title,start_date,start_time,end_date,end_time,notes,data_json) VALUES (?,?,?,?,?,?,?,?,?)');foreach($events as $e){$es->execute([$tripId,clean_string($e['type']??$e['event_type']??null,50)?:'poi',clean_string($e['title']??null,255)?:'Event',clean_string($e['date']??$e['start_date']??null,20)?:date('Y-m-d'),clean_string($e['time']??$e['start_time']??null,20),clean_string($e['end_date']??null,20),clean_string($e['end_time']??null,20),clean_string($e['notes']??null,5000),json_encode($e['data']??[],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)]);} $ps=$pdo->prepare('INSERT INTO packing_items (trip_id,item_text,place,packed,category) VALUES (?,?,?,?,?)');foreach($packing as $p){$ps->execute([$tripId,clean_string($p['text']??$p['item_text']??null,255)?:'Item',clean_string($p['place']??null,255),!empty($p['packed'])?1:0,clean_string($p['category']??null,100)]);} $bs=$pdo->prepare('INSERT INTO budget_items (trip_id,category,item_name,amount,currency,paid) VALUES (?,?,?,?,?,?)');foreach($budget as $b){$bs->execute([$tripId,clean_string($b['category']??null,100),clean_string($b['name']??$b['item_name']??null,255)?:'Item',(float)($b['amount']??0),clean_string($b['currency']??'NOK',10)?:'NOK',!empty($b['paid'])?1:0]);}$pdo->commit();json_response(['trip_id'=>$tripId],201);}catch(Throwable $e){$pdo->rollBack();json_response(['error'=>'Import failed','detail'=>$e->getMessage()],500);} 
